import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for fused matmul + relu + division with tiling
fused_linear_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

template<typename T>
__global__ void fused_linear_relu_div_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    const int batch_size,
    const int in_features,
    const int out_features,
    const T divisor) {

    // Shared memory for tile of input and weight matrices
    __shared__ T shared_mem[2 * 32 * 32];
    T* input_tile = shared_mem;
    T* weight_tile = shared_mem + 32 * 32;

    const int tile_size = 32;
    const int row = blockIdx.y * tile_size + threadIdx.y;
    const int col = blockIdx.x * tile_size + threadIdx.x;

    T sum = static_cast<T>(0);

    // Loop over tiles
    for (int tile = 0; tile < (in_features + tile_size - 1) / tile_size; ++tile) {
        int input_col = tile * tile_size + threadIdx.x;
        int weight_row = tile * tile_size + threadIdx.y;

        // Load input tile
        if (row < batch_size && input_col < in_features) {
            input_tile[threadIdx.y * tile_size + threadIdx.x] = input[row * in_features + input_col];
        } else {
            input_tile[threadIdx.y * tile_size + threadIdx.x] = static_cast<T>(0);
        }

        // Load weight tile (transposed for better memory access)
        if (col < out_features && weight_row < in_features) {
            weight_tile[threadIdx.x * tile_size + threadIdx.y] = weight[col * in_features + weight_row];
        } else {
            weight_tile[threadIdx.x * tile_size + threadIdx.y] = static_cast<T>(0);
        }

        __syncthreads();

        // Compute partial sum for this tile
        #pragma unroll
        for (int k = 0; k < tile_size; ++k) {
            sum += input_tile[threadIdx.y * tile_size + k] * weight_tile[threadIdx.x * tile_size + k];
        }

        __syncthreads();
    }

    // Write result with fused ReLU and division
    if (row < batch_size && col < out_features) {
        if (bias) {
            sum += bias[col];
        }

        if (sum > static_cast<T>(0)) {
            output[row * out_features + col] = sum / divisor;
        } else {
            output[row * out_features + col] = static_cast<T>(0);
        }
    }
}

torch::Tensor fused_linear_relu_div_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float divisor) {

    const int batch_size = input.size(0);
    const int in_features = input.size(1);
    const int out_features = weight.size(0);

    auto output = torch::empty({batch_size, out_features},
                              torch::TensorOptions()
                              .dtype(input.dtype())
                              .device(input.device()));

    // Configure thread blocks with tiling
    const int tile_size = 32;
    dim3 block_size(tile_size, tile_size);
    dim3 grid_size((out_features + tile_size - 1) / tile_size,
                  (batch_size + tile_size - 1) / tile_size);

    // Shared memory size: input tile + weight tile
    size_t shared_mem_size = 2 * tile_size * tile_size * sizeof(float);

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_linear_relu_div_cuda", [&] {
        scalar_t divisor_scalar = static_cast<scalar_t>(divisor);
        fused_linear_relu_div_kernel<scalar_t><<<grid_size, block_size, shared_mem_size>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            batch_size,
            in_features,
            out_features,
            divisor_scalar
        );
    });

    return output;
}
"""

fused_linear_cpp_source = """
torch::Tensor fused_linear_relu_div_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float divisor);
"""

# Compile the inline CUDA code
fused_linear_op = load_inline(
    name="fused_linear_relu_div",
    cpp_sources=fused_linear_cpp_source,
    cuda_sources=fused_linear_source,
    functions=["fused_linear_relu_div_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    extra_include_paths=[],
    with_cuda=True,
)

class ModelNew(nn.Module):
    """
    Optimized model with fused matrix multiplication, ReLU, and division.
    """
    def __init__(self, in_features, out_features, divisor):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.divisor = divisor

        # Initialize weights and bias like nn.Linear
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        self.bias = nn.Parameter(torch.empty(out_features))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

        self.fused_op = fused_linear_op

    def forward(self, x):
        return self.fused_op.fused_linear_relu_div_cuda(x, self.weight, self.bias, self.divisor)

